// Sample regulatory changes for testing.
// In production: replace with HTTP Request nodes reading RSS feeds from
// EUR-Lex, FTC, ICO, GDPR.eu, FinCEN, FCA, etc.
const sampleChanges = [
  { id: 'reg_001', title: 'EU AI Act — High-risk system classification guidelines published', source: 'EUR-Lex', jurisdiction: 'EU', url: 'https://example.com/eu-ai-act-guidelines', published_at: '2026-07-12', summary: 'European Commission published final guidelines on what constitutes a high-risk AI system under Article 6. Systems used in employment and credit decisions are explicitly included.' },
  { id: 'reg_002', title: 'FTC finalises rule on AI-generated endorsements and testimonials', source: 'FTC.gov', jurisdiction: 'US', url: 'https://example.com/ftc-ai-endorsements', published_at: '2026-07-10', summary: 'FTC final rule requires disclosure when AI generates reviews or testimonials. Enforcement begins 90 days after publication. Penalties up to $50,000 per violation.' },
  { id: 'reg_003', title: 'UK ICO updates guidance on automated decision-making under UK GDPR', source: 'ICO.org.uk', jurisdiction: 'UK', url: 'https://example.com/ico-adm-guidance', published_at: '2026-07-09', summary: 'Updated guidance clarifies when organisations must provide human review for automated decisions. Applies to any decision producing legal or similarly significant effects.' },
  { id: 'reg_004', title: 'California AB-2013: Training data transparency for AI products (effective Jan 2027)', source: 'California Legislature', jurisdiction: 'US-CA', url: 'https://example.com/ca-ab2013', published_at: '2026-07-08', summary: 'Signed into law. Requires AI developers to publish summary of training data used. Applies to products used by California consumers.' },
  { id: 'reg_005', title: 'NIST AI RMF v2.0 released — new guidance on AI audit trails', source: 'NIST.gov', jurisdiction: 'US', url: 'https://example.com/nist-ai-rmf-v2', published_at: '2026-07-07', summary: 'Non-binding but widely referenced. New section on documenting AI model decisions for audit purposes. Expected to influence enterprise procurement requirements.' },
  { id: 'reg_006', title: 'Minor update to GDPR cookie consent template — no material change', source: 'EDPB', jurisdiction: 'EU', url: 'https://example.com/edpb-cookie-update', published_at: '2026-07-06', summary: 'Template wording update. No change to consent requirements. Low relevance.' }
];
return [{ json: { changes: sampleChanges, total: sampleChanges.length, fetched_at: new Date().toISOString() } }];

const { changes, total, fetched_at } = $input.first().json;
if (!changes || !Array.isArray(changes) || changes.length === 0) {
  return [{ json: { _skip: true, reason: 'No regulatory changes found in this run' } }];
}
// Filter to configured jurisdictions if env var is set
const configured = ($env.REGULATORY_JURISDICTIONS || '').split(',').map(j => j.trim().toUpperCase()).filter(Boolean);
const filtered = configured.length > 0
  ? changes.filter(c => configured.some(j => c.jurisdiction.toUpperCase().startsWith(j)))
  : changes;
return [{ json: { changes: filtered, total_raw: total, total_filtered: filtered.length, fetched_at } }];

const { changes, fetched_at } = $input.first().json;
const productAreas = $env.REGULATORY_PRODUCT_AREAS || 'data-privacy,ai-model-outputs,billing,user-data';
const changesText = changes.map((c, i) =>
  `[${i+1}] ID: ${c.id}\nTitle: ${c.title}\nJurisdiction: ${c.jurisdiction}\nPublished: ${c.published_at}\nSummary: ${c.summary}`
).join('\n\n');
const system = `You are a regulatory compliance analyst. You read regulatory updates and assess which product areas they affect. You are precise — you only flag items with genuine relevance. Return ONLY valid JSON.`;
const user = `Review these ${changes.length} regulatory updates and map each to the product areas that are affected.

Our product areas: ${productAreas}

Regulatory updates:
${changesText}

Return JSON:
{
  "assessed_changes": [
    {
      "id": "string",
      "title": "string",
      "jurisdiction": "string",
      "relevance": "high|medium|low|none",
      "affected_product_areas": ["string"],
      "required_action": "string — what the team needs to do, or 'Monitor only'",
      "deadline": "string or null",
      "confidence": "low|medium|high"
    }
  ],
  "high_priority_count": number,
  "summary": "string — one paragraph overview of the most important changes"
}`;
return [{ json: { ...($input.first().json), system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Mapping Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No LLM content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.assessed_changes || !Array.isArray(parsed.assessed_changes)) {
  return [{ json: { _error: true, reason: 'Missing assessed_changes array' } }];
}
return [{ json: { _error: false, assessment: parsed, meta: { fetched_at: upstream.fetched_at, total_filtered: upstream.total_filtered } } }];

const { assessment: a, meta: m } = $input.first().json;
const high = a.assessed_changes.filter(c => c.relevance === 'high');
const medium = a.assessed_changes.filter(c => c.relevance === 'medium');
const changeLines = a.assessed_changes
  .filter(c => c.relevance !== 'none')
  .map(c => `[${c.relevance.toUpperCase()}] ${c.title} (${c.jurisdiction})\n  Areas: ${c.affected_product_areas.join(', ') || 'none'}\n  Action: ${c.required_action}\n  Deadline: ${c.deadline || 'none specified'}\n  Confidence: ${c.confidence}`)
  .join('\n\n');
const report = [
  `REGULATORY CHANGE MONITOR`,
  `Fetched: ${m.fetched_at} | Updates reviewed: ${m.total_filtered}`,
  `High priority: ${high.length} | Medium priority: ${medium.length}`,
  ``,
  `SUMMARY: ${a.summary}`,
  ``,
  `RELEVANT CHANGES:`,
  changeLines || '  (none with relevance above none)',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
